import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import App from './App'; // Assuming this is your main App component
import Dublin from './components/dublin/Dublin';
import Main from './components/main/Main';
import MainView from './components/main-view/main-view';
import Wicklow from './components/wicklow/Wicklow';
import County from './components/county/County';
import MapTransitionOverlay from './components/overlay/MapTransitionOverlay';

const RoutesComponent = () => {
  return (
    <Router>
      <Routes>
        <Route
          path="/"
          element={
            <MainView />
          }
        />
        <Route
          path="/dublin"
          element={
            <County
                 />
          }
        />
        <Route
          path="/wicklow"
          element={
            <County

            />
          }
        />
        {/* Add other routes as needed */}
        <Route path="/main" element={<Main />} />
        <Route path="/dublin" element={<Dublin />} />
        <Route path="/wicklow" element={<Wicklow />} />
        <Route path="/map-transition" element={<MapTransitionOverlay />} />
      </Routes>
    </Router>
  );
};

export default RoutesComponent;
